  const selectedRoundOperationsFlags = useMemo(() => {
    const flags = new Set<string>();

    if (!selectedRoundScheduleRows.length) flags.add("No room schedule");
    selectedRoundTacticalBoardRows.forEach((row) => {
      row.flags.forEach((flag) => {
        const normalizedFlag = asText(flag);
        if (!normalizedFlag) return;
        if (normalizedFlag === "Missing SP" && selectedRoundCoverageShortage <= 0) return;
        flags.add(normalizedFlag);
      });
    });
    if (selectedRoundCoverageShortage > 0) {
      flags.add(`${selectedRoundCoverageShortage} room${selectedRoundCoverageShortage === 1 ? "" : "s"} still needs SP`);
    } else if (selectedRoundRoomMappingGap > 0) {
      flags.add(`Needs room mapping for ${selectedRoundRoomMappingGap} room${selectedRoundRoomMappingGap === 1 ? "" : "s"}`);
    }
    if (selectedRoundEmptySlots !== null && selectedRoundEmptySlots > 0) {
      flags.add(`${selectedRoundEmptySlots} empty learner slot${selectedRoundEmptySlots === 1 ? "" : "s"}`);
    }
    return Array.from(flags);
  }, [
    selectedRoundCoverageShortage,
    selectedRoundEmptySlots,
    selectedRoundRoomMappingGap,
    selectedRoundScheduleRows,
    selectedRoundTacticalBoardRows,
  ]);
  const feedbackMinutesFromMetadata = useMemo(
    () => parseIntegerNoteValue(eventEditor.notes || event?.notes, "Feedback / Break Length"),
    [event?.notes, eventEditor.notes]
  );
  const selectedRoundAnnouncementTimeline = useMemo(() => {
    if (!selectedRotationRound) {
      return [] as Array<{
        key: string;
        timeLabel: string;
        phaseLabel: string;
        announcement: string;
        detail?: string;
      }>;
    }

    const selectedRoundTiming = getNormalizedRotationRoundTiming(
      selectedRotationRound,
      getSameDateRotationRounds(selectedRotationRound, rotationRounds)
    );
    const startMinutes = selectedRoundTiming?.startMinutes ?? null;
    const encounterEndMinutes = selectedRoundTiming?.endMinutes ?? null;
    if (startMinutes === null || encounterEndMinutes === null || encounterEndMinutes <= startMinutes) {
      return [] as Array<{
        key: string;
        timeLabel: string;
        phaseLabel: string;
        announcement: string;
        detail?: string;
      }>;
    }

    const nextRound = rotationRounds[activeSelectedRotationRoundIndex + 1] || null;
    const nextRoundTiming = nextRound
      ? getNormalizedRotationRoundTiming(nextRound, getSameDateRotationRounds(nextRound, rotationRounds))
      : null;
    const nextRoundStartMinutes = nextRoundTiming?.startMinutes ?? null;
    const safeFeedbackMinutes = Math.max(feedbackMinutesFromMetadata, 0);
    const feedbackEndMinutes =
      safeFeedbackMinutes > 0
        ? nextRoundStartMinutes !== null
          ? Math.min(encounterEndMinutes + safeFeedbackMinutes, nextRoundStartMinutes)
          : encounterEndMinutes + safeFeedbackMinutes
        : encounterEndMinutes;

    const timeline: Array<{
      key: string;
      timeLabel: string;
      phaseLabel: string;
      announcement: string;
      detail?: string;
    }> = [
      {
        key: `${selectedRotationRound.key}-prepare`,
        timeLabel: formatMinutesAsClockLabel(Math.max(startMinutes - 1, 0)),
        phaseLabel: "Prepare",
        announcement: "SPs, please prepare.",
        detail: "1 minute before encounter start",
      },
      {
        key: `${selectedRotationRound.key}-start`,
        timeLabel: formatMinutesAsClockLabel(startMinutes),
        phaseLabel: "Start",
        announcement: "You may now begin your encounter.",
      },
    ];

    if (encounterEndMinutes - startMinutes >= 5) {
      timeline.push({
        key: `${selectedRotationRound.key}-warning`,
        timeLabel: formatMinutesAsClockLabel(encounterEndMinutes - 5),
        phaseLabel: "5-Min Warning",
        announcement: "You have 5 minutes remaining in your encounter.",
      });
    }

    timeline.push({
      key: `${selectedRotationRound.key}-feedback-start`,
      timeLabel: formatMinutesAsClockLabel(encounterEndMinutes),
      phaseLabel: "Feedback",
      announcement: "Encounter has ended. SPs, please begin feedback.",
      detail: safeFeedbackMinutes > 0 ? `${safeFeedbackMinutes} minute feedback window` : undefined,
    });

    if (safeFeedbackMinutes > 0 && feedbackEndMinutes > encounterEndMinutes) {
      timeline.push({
        key: `${selectedRotationRound.key}-session-end`,
        timeLabel: formatMinutesAsClockLabel(feedbackEndMinutes),
        phaseLabel: "Session End",
        announcement: "Your session has ended. Please leave the simulation.",
      });
    }

    let cursorMinutes = feedbackEndMinutes;
    visibleSelectedRoundDayBlocks.forEach((block, index) => {
      const blockMinutes = Math.max(parseDurationMinutes(block.detail), 0);
      const blockStart = cursorMinutes;
      const blockEnd = blockMinutes > 0 ? cursorMinutes + blockMinutes : cursorMinutes;
      const normalizedLabel = asText(block.label).toLowerCase();
      const phaseLabel = normalizedLabel.includes("checklist")
        ? "Checklist"
        : normalizedLabel.includes("soap")
          ? "SOAP Notes"
          : normalizedLabel.includes("feedback")
            ? "Feedback"
            : normalizedLabel.includes("debrief")
              ? "Debrief"
              : normalizedLabel.includes("break") || normalizedLabel.includes("lunch") || normalizedLabel.includes("transition")
                ? "Break/Transition"
                : block.label || "Day Block";
      timeline.push({
        key: `${selectedRotationRound.key}-block-${index}`,
        timeLabel:
          blockEnd > blockStart ? formatMinuteRange(blockStart, blockEnd) : formatMinutesAsClockLabel(blockStart),
        phaseLabel,
        announcement: block.label,
        detail: block.detail,
      });
      cursorMinutes = blockEnd;
    });

    if (nextRoundStartMinutes !== null && nextRoundStartMinutes > cursorMinutes) {
      timeline.push({
        key: `${selectedRotationRound.key}-transition`,
        timeLabel: formatMinuteRange(cursorMinutes, nextRoundStartMinutes),
        phaseLabel: "Break/Transition",
        announcement: "Turnaround / transition time.",
      });
      timeline.push({
        key: `${selectedRotationRound.key}-next-prepare`,
        timeLabel: formatMinutesAsClockLabel(Math.max(nextRoundStartMinutes - 1, 0)),
        phaseLabel: "Prepare",
        announcement: "SPs, please prepare.",
        detail: `Preparing for Round ${activeSelectedRotationRoundIndex + 2}`,
      });
    }

    return timeline;
  }, [
    activeSelectedRotationRoundIndex,
    feedbackMinutesFromMetadata,
    rotationRounds,
    selectedRotationRound,
    visibleSelectedRoundDayBlocks,
  ]);
  const selectedRoundOperationsNotes = useMemo(
    () =>
      [
        asText(trainingMetadata.training_notes),
        asText(trainingMetadata.contact_internal_notes),
        asText(parseNoteValue(event?.notes, "Operations Notes")),
        asText(parseNoteValue(event?.notes, "Operations Reminder")),
      ].filter(Boolean),
    [event?.notes, trainingMetadata.contact_internal_notes, trainingMetadata.training_notes]
  );
  const eventPollLink =
    typeof window !== "undefined" && id
      ? `${window.location.origin}/events/${encodeURIComponent(id)}/poll`
      : id
        ? `/events/${encodeURIComponent(id)}/poll`
        : "/events";
  const activePollSelectedSpIds = selectedPollSpIds.length
    ? selectedPollSpIds
    : pollSelectedSpIdsFromMetadata;
  const activePollSelectedSpEmails = pollSelectedEmails.length
    ? pollSelectedEmails
    : pollSelectedSpEmailsFromMetadata;
  const pollResponderEntries = useMemo(() => {
    const byId = new Map<string, {
      sp: SPRow;
      assignment: AssignmentRow | null;
      assignmentStatus: AssignmentStatus | null;
      pollResponseStatus: PollResponseStatus;
      availabilityMatch: AvailabilityMatchStatus;
      isAssigned: boolean;
      isConfirmed: boolean;
      isActive: boolean;
      isTelehealthReady: boolean;
      hasPtPreferred: boolean;
      importedResponse: ImportedPollResponseRecord | null;
      importedMatchConfidence: number;
    }>();

    activePollSelectedSpIds.forEach((spId) => {
      const sp = spsById.get(String(spId));
      if (!sp) return;
      const assignment = assignmentsBySpId.get(String(sp.id)) || null;
      const assignmentStatus = assignment ? getAssignmentStatus(assignment) : null;
      const importedResponse = importedPollResponsesBySpId.get(String(sp.id)) || null;
      byId.set(String(sp.id), {
        sp,
        assignment,
        assignmentStatus,
        pollResponseStatus: getEffectivePollResponseStatus(assignment?.notes, importedResponse),
        availabilityMatch: availabilityMatchBySpId.get(sp.id)?.status || "unknown",
        isAssigned: Boolean(assignment),
        isConfirmed: assignment ? isAssignmentConfirmed(assignment) : false,
        isActive: isActiveSp(sp),
        isTelehealthReady: hasTelehealth(sp),
        hasPtPreferred: hasPtPreferred(sp),
        importedResponse,
        importedMatchConfidence: importedResponse?.matchConfidence || 0,
      });
    });

    activePollSelectedSpEmails.forEach((email) => {
      const sp = spByEmail.get(normalizeEmail(email));
      if (!sp) return;
      if (byId.has(String(sp.id))) return;
      const assignment = assignmentsBySpId.get(String(sp.id)) || null;
      const assignmentStatus = assignment ? getAssignmentStatus(assignment) : null;
      const importedResponse = importedPollResponsesBySpId.get(String(sp.id)) || null;
      byId.set(String(sp.id), {
        sp,
        assignment,
        assignmentStatus,
        pollResponseStatus: getEffectivePollResponseStatus(assignment?.notes, importedResponse),
        availabilityMatch: availabilityMatchBySpId.get(sp.id)?.status || "unknown",
        isAssigned: Boolean(assignment),
        isConfirmed: assignment ? isAssignmentConfirmed(assignment) : false,
        isActive: isActiveSp(sp),
        isTelehealthReady: hasTelehealth(sp),
        hasPtPreferred: hasPtPreferred(sp),
        importedResponse,
        importedMatchConfidence: importedResponse?.matchConfidence || 0,
      });
    });

    importedPollResponsesBySpId.forEach((importedResponse) => {
      const sp = spsById.get(importedResponse.matchedSpId);
      if (!sp) return;
      if (byId.has(String(sp.id))) return;
      const assignment = assignmentsBySpId.get(String(sp.id)) || null;
      const assignmentStatus = assignment ? getAssignmentStatus(assignment) : null;
      byId.set(String(sp.id), {
        sp,
        assignment,
        assignmentStatus,
        pollResponseStatus: getEffectivePollResponseStatus(assignment?.notes, importedResponse),
        availabilityMatch: availabilityMatchBySpId.get(sp.id)?.status || "unknown",
        isAssigned: Boolean(assignment),
        isConfirmed: assignment ? isAssignmentConfirmed(assignment) : false,
        isActive: isActiveSp(sp),
        isTelehealthReady: hasTelehealth(sp),
        hasPtPreferred: hasPtPreferred(sp),
        importedResponse,
        importedMatchConfidence: importedResponse.matchConfidence || 0,
      });
    });

    return Array.from(byId.values()).sort((a, b) => {
      const responseRank = { available: 0, maybe: 1, no_response: 2, not_available: 3 } satisfies Record<PollResponseStatus, number>;
      const assignmentRank = a.isConfirmed === b.isConfirmed ? 0 : a.isConfirmed ? -1 : 1;
      const responseCompare = responseRank[a.pollResponseStatus] - responseRank[b.pollResponseStatus];
      if (responseCompare !== 0) return responseCompare;
      if (assignmentRank !== 0) return assignmentRank;
      const availabilityCompare =
        getAvailabilityMatchRank(a.availabilityMatch) - getAvailabilityMatchRank(b.availabilityMatch);
      if (availabilityCompare !== 0) return availabilityCompare;
      const importedCompare = b.importedMatchConfidence - a.importedMatchConfidence;
      if (importedCompare !== 0) return importedCompare;
      return getFullName(a.sp).localeCompare(getFullName(b.sp));
    });
  }, [
    activePollSelectedSpEmails,
    activePollSelectedSpIds,
    assignmentsBySpId,
    availabilityMatchBySpId,
    importedPollResponsesBySpId,
    spByEmail,
    spsById,
  ]);
  const availablePollResponders = useMemo(
    () => pollResponderEntries.filter((entry) => entry.pollResponseStatus === "available"),
    [pollResponderEntries]
  );
  const maybePollResponders = useMemo(
    () => pollResponderEntries.filter((entry) => entry.pollResponseStatus === "maybe"),
    [pollResponderEntries]
  );
  const unavailablePollResponders = useMemo(
    () => pollResponderEntries.filter((entry) => entry.pollResponseStatus === "not_available"),
    [pollResponderEntries]
  );
  const noResponsePollResponders = useMemo(
    () => pollResponderEntries.filter((entry) => entry.pollResponseStatus === "no_response"),
    [pollResponderEntries]
  );
  const pollSelectedEntries = useMemo(
    () =>
      pollSelectedSps.map((sp) => ({
        sp,
        pollResponseStatus:
          pollResponderEntries.find((entry) => entry.sp.id === sp.id)?.pollResponseStatus || "no_response",
      })),
    [pollResponderEntries, pollSelectedSps]
  );
  const pollResponseRate = pollResponderEntries.length
    ? Math.round(((availablePollResponders.length + maybePollResponders.length + unavailablePollResponders.length) / pollResponderEntries.length) * 100)
    : 0;
  const coverageGap = Math.max(needed - confirmedCount, 0);
  const availableCoverageCount = availablePollResponders.filter(
    (entry) => entry.isActive && entry.pollResponseStatus === "available" && entry.assignmentStatus !== "declined"
  ).length;
  const coverageRiskTone =
    needed <= 0 || confirmedCount >= needed
      ? "green"
      : confirmedCount + availableCoverageCount >= needed
        ? "yellow"
        : "red";
  const staffingHealthLabel =
    needed <= 0
      ? selectedStaffingCount > 0
        ? "Selected roster on file"
        : "No SP target set"
      : coverageRiskTone === "green"
        ? "Coverage met"
      : coverageRiskTone === "yellow"
        ? `Short by ${coverageGap} primary`
        : `Understaffed by ${coverageGap} primary`;
  const firstLiveRotationStartMinutes = liveFlowBlocks.find((block) => block.tone === "rotation")?.startMinutes ?? null;
  const missingAssignedCount = useMemo(
    () =>
      sortedAssignments.filter(
        (assignment) =>
          getAssignmentStatus(assignment) !== "declined" &&
          getAssignmentStatus(assignment) !== "no_show" &&
          assignment.training_attended !== true
      ).length,
    [sortedAssignments]
  );
  const noShowAssignedCount = useMemo(() => {
    if (firstLiveRotationStartMinutes === null || simulatedLiveMinutes < firstLiveRotationStartMinutes + 15) {
      return 0;
    }
    return sortedAssignments.filter(
      (assignment) =>
        getAssignmentStatus(assignment) !== "declined" &&
        getAssignmentStatus(assignment) !== "no_show" &&
        assignment.training_attended !== true
    ).length;
  }, [firstLiveRotationStartMinutes, simulatedLiveMinutes, sortedAssignments]);
  const payrollReadyCount = useMemo(
    () =>
      sortedAssignments.filter((assignment) => {
        const status = getAssignmentStatus(assignment);
        return status !== "declined" && status !== "no_show" && assignment.training_attended === true;
      }).length,
    [sortedAssignments]
  );
  const backupAvailableCount =
    sortedAssignments.filter((assignment) => getAssignmentStatus(assignment) === "backup").length +
    maybePollResponders.filter((entry) => !entry.isAssigned).length;
  const liveStaffingHealthTone =
    shortageCount <= 0 && missingAssignedCount === 0
      ? "green"
      : shortageCount <= 0 && backupAvailableCount > 0
        ? "yellow"
        : "red";
  const activeCoverageRiskRooms = useMemo(() => {
    if (!currentLiveRoomDisplayEntries.length) return [] as string[];
    return currentLiveRoomDisplayEntries.flatMap(({ roomName, sourceIndex }, index) => {
      const assignment = sourceIndex >= 0 ? sortedAssignments[sourceIndex] : null;
      const status = assignment ? getAssignmentStatus(assignment) : null;
      return !assignment || status === "backup" || status === "declined" || status === "no_show"
        ? [roomName || `Room ${index + 1}`]
        : [];
    });
  }, [currentLiveRoomDisplayEntries, sortedAssignments]);
  const liveAlerts = useMemo(() => {
    const alerts: Array<{ tone: "info" | "warning" | "danger"; message: string }> = [];
    if (nextLiveBlock) {
      const minutesUntil = nextLiveBlock.startMinutes - simulatedLiveMinutes;
      if (minutesUntil >= 0 && minutesUntil <= 5) {
        alerts.push({
          tone: nextLiveBlock.tone === "rotation" ? "warning" : "info",
          message: `${nextLiveBlock.label} begins in ${minutesUntil} minute${minutesUntil === 1 ? "" : "s"}.`,
        });
      }
    }
    if (missingAssignedCount > 0) {
      alerts.push({
        tone: noShowAssignedCount > 0 ? "danger" : "warning",
        message:
          noShowAssignedCount > 0
            ? `${noShowAssignedCount} SP${noShowAssignedCount === 1 ? "" : "s"} now read as no-show.`
            : `${missingAssignedCount} SP${missingAssignedCount === 1 ? "" : "s"} not checked in yet.`,
      });
    }
    if (activeCoverageRiskRooms.length > 0) {
      alerts.push({
        tone: shortageCount > 0 ? "danger" : "warning",
        message:
          activeCoverageRiskRooms.length === 1
            ? shortageCount > 0
              ? `${activeCoverageRiskRooms[0]} needs staffing attention.`
              : `${activeCoverageRiskRooms[0]} needs room mapping review.`
            : shortageCount > 0
              ? `Review room coverage in ${activeCoverageRiskRooms.join(", ")}.`
              : `Review room mapping for ${activeCoverageRiskRooms.join(", ")}.`,
      });
    }
    if (shortageCount > 0) {
      alerts.push({
        tone: liveStaffingHealthTone === "yellow" ? "warning" : "danger",
        message: `Primary staffing still short by ${shortageCount}.`,
      });
    }
    return alerts.slice(0, 4);
  }, [
    activeCoverageRiskRooms,
    liveStaffingHealthTone,
    missingAssignedCount,
    nextLiveBlock,
    noShowAssignedCount,
    shortageCount,
    simulatedLiveMinutes,
  ]);
  const liveBlueprintRoomEntries = useMemo(() => {
    if (currentLiveRoomDisplayEntries.length) return currentLiveRoomDisplayEntries;
    if (selectedRoundRoomSlotEntries.length) return selectedRoundRoomSlotEntries;

    const fallbackRound = rotationRounds[0] || null;
    const fallbackRoomCount = fallbackRound ? 0 : 8;

    return buildFullRoomSlotsForRound(fallbackRound, {
      metadataRoomCount: effectiveRoomCount,
      fallbackRoomCount,
      roomContext: roomNamingContext,
    });
  }, [
    currentLiveRoomDisplayEntries,
    effectiveRoomCount,
    roomNamingContext,
    rotationRounds,
    selectedRoundRoomSlotEntries
  ]);
  const liveBlueprintExplicitAssignments = useMemo(
    () =>
      liveBlueprintRoomEntries.map(({ sourceIndex }) =>
        sourceIndex >= 0 ? confirmedAssignments[sourceIndex] || null : null
      ),
    [confirmedAssignments, liveBlueprintRoomEntries]
  );
  const liveBlueprintRoomAssignmentPlan = useMemo(
    () =>
      buildRoomSlotAssignmentPlan(
        liveBlueprintRoomEntries,
        liveBlueprintExplicitAssignments,
        confirmedAssignments,
        roomNamingContext
      ),
    [confirmedAssignments, roomNamingContext, liveBlueprintExplicitAssignments, liveBlueprintRoomEntries]
  );
  const liveBlueprintBaseHighestRoomNumber = useMemo(
    () => getHighestRoomDisplayNumber(liveBlueprintRoomEntries.map((entry) => entry.roomName)),
    [liveBlueprintRoomEntries]
  );
  const liveAdjustmentAssignedStandbyIds = useMemo(
    () =>
      new Set(
        Object.values(liveRoomAdjustments)
          .map((adjustment) => asText(adjustment.standbyAssignmentId))
          .filter(Boolean)
      ),
    [liveRoomAdjustments]
  );
  const liveRestoredAssignmentRoomById = useMemo(() => {
    const next = new Map<string, string>();
    Object.entries(liveRoomAdjustments).forEach(([roomKey, adjustment]) => {
      const restoredId = asText(adjustment.restoredAssignmentId);
      if (restoredId) next.set(restoredId, roomKey);
    });
    return next;
  }, [liveRoomAdjustments]);
  const liveBlueprintBaseRooms = useMemo(
    () =>
      liveBlueprintRoomEntries.map(({ roomName, sourceIndex }, index) => {
        const adjustmentKey = asText(roomName).toLowerCase();
        const adjustment = liveRoomAdjustments[adjustmentKey] || {};
        const boardRow =
          currentLiveRoomBoardRows.find((row) => asText(row.roomName).toLowerCase() === asText(roomName).toLowerCase()) ||
          (sourceIndex >= 0 ? currentLiveRoomBoardRows.find((row) => row.sourceIndex === sourceIndex) : null) ||
          currentLiveRoomBoardRows[index] ||
          null;
        const roomNumber = getRoomDisplayNumber(roomName);
        const scheduleRow =
          currentLiveReferenceScheduleRows.find((row) => {
            const rowNumber = getRoomDisplayNumber(row.roomName);
            return roomNumber !== null && rowNumber === roomNumber;
          }) ||
          currentLiveReferenceScheduleRows.find(
            (row) => asText(row.roomName).toLowerCase() === asText(roomName).toLowerCase()
          ) ||
          selectedRoundScheduleRows.find((row) => {
            const rowNumber = getRoomDisplayNumber(row.roomName);
            return roomNumber !== null && rowNumber === roomNumber;
          }) ||
          selectedRoundScheduleRows.find(
            (row) => asText(row.roomName).toLowerCase() === asText(roomName).toLowerCase()
          ) ||
          null;
        const projection = liveBlueprintRoomAssignmentPlan.assignments[index];
        const restoredAssignment =
          asText(adjustment.restoredAssignmentId)
            ? confirmedAssignments.find((item) => item.id === adjustment.restoredAssignmentId) || null
            : null;
        const plannedAssignment = boardRow?.assignment || projection?.assignment || null;
        const plannedAssignmentOverrideRoom = plannedAssignment?.id
          ? liveRestoredAssignmentRoomById.get(plannedAssignment.id)
          : "";
        const assignment =
          restoredAssignment ||
          (plannedAssignmentOverrideRoom && plannedAssignmentOverrideRoom !== adjustmentKey ? null : plannedAssignment);
        const sp = assignment
          ? (assignment.sp_id ? spsById.get(assignment.sp_id) || null : null)
          : null;
        const assignmentSource = restoredAssignment
          ? "restored"
          : assignment
            ? projection?.isExplicit
              ? "explicit"
              : "auto"
            : "missing";
        const standbyAssignment =
          asText(adjustment.standbyAssignmentId)
            ? backupAssignments.find((item) => item.id === adjustment.standbyAssignmentId) || null
            : null;
        const standbySp = standbyAssignment?.sp_id ? spsById.get(standbyAssignment.sp_id) || null : null;
        const assignmentStatus = assignment ? getAssignmentStatus(assignment) : null;
        const liveAttendanceMetadata = assignment ? parseLiveAttendanceMetadata(assignment.notes) : emptyLiveAttendanceMetadata();
        const manualStatus = asText(liveAttendanceMetadata.status).toLowerCase();
        const manualUpdatedAt = asText(liveAttendanceMetadata.updatedAt);
        const checkedIn = assignment?.training_attended === true;
        const autoNoShow =
          manualStatus !== "cleared" &&
          manualStatus !== "late" &&
          Boolean(assignment) &&
          firstLiveRotationStartMinutes !== null &&
          simulatedLiveMinutes >= firstLiveRotationStartMinutes + 15;
        const autoLate =
          manualStatus !== "cleared" &&
          (boardRow?.status === "delayed" ||
            (Boolean(assignment) &&
              assignmentStatus !== "declined" &&
              firstLiveRotationStartMinutes !== null &&
              simulatedLiveMinutes > firstLiveRotationStartMinutes));
        const noShow =
          !checkedIn &&
          (manualStatus === "no_show" || assignmentStatus === "no_show" || autoNoShow);
        const late =
          !checkedIn &&
          !noShow &&
          (manualStatus === "late" || autoLate);
        const status = checkedIn
          ? "checked_in"
          : noShow
            ? "no_show"
            : late
              ? "late"
              : assignment
                ? "awaiting"
                : "empty";

        return {
          key: boardRow?.key || `blueprint-room-${index}`,
          roomName,
          assignment,
          sp,
          spName: sp ? getFullName(sp) : "",
          initials: sp ? getInitials(getFullName(sp)) : String(index + 1),
          checkedAt:
            checkedIn
              ? boardRow?.checkedAt || (assignment ? formatAttendanceTimestamp(assignment.training_checked_in_at) : "")
              : manualUpdatedAt
                ? formatAttendanceTimestamp(manualUpdatedAt)
                : "",
          actionTimestamp: checkedIn
            ? asText(assignment?.training_checked_in_at) || manualUpdatedAt
            : manualUpdatedAt,
          status,
          statusLabel:
            status === "checked_in"
              ? "Checked In"
              : status === "no_show"
                ? "No-show"
                : status === "late"
                  ? "Late"
                  : status === "awaiting"
                    ? "Awaiting"
                    : "Standby",
          isCurrentRotationRoom: Boolean(currentLiveRoomDisplayEntries.length && index < currentLiveRoomDisplayEntries.length),
          issueNote: boardRow?.issueNote || "",
          delayMinutes: boardRow?.delayMinutes || 0,
          learnerLabel: isAssignedLearnerRoomLabel(boardRow?.learnerLabel)
            ? asText(boardRow?.learnerLabel)
            : getLearnerRoomAssignmentLabel(scheduleRow?.learnerLabels || []),
          encounterLabel: boardRow?.encounterLabel || "Case not assigned",
          standbyAssignment,
          standbySp,
          standbySpName: standbySp ? getFullName(standbySp) : "",
          standbyExpanded: Boolean(adjustment.expanded || standbyAssignment),
          adjustmentKey,
          isTemporaryRoom: false,
          assignmentSource,
        };
      }),
    [
      backupAssignments,
      confirmedAssignments,
      currentLiveRoomDisplayEntries.length,
      currentLiveRoomBoardRows,
      currentLiveReferenceScheduleRows,
      firstLiveRotationStartMinutes,
      liveBlueprintRoomEntries,
      liveBlueprintRoomAssignmentPlan.assignments,
      liveRestoredAssignmentRoomById,
      liveRoomAdjustments,
      selectedRoundScheduleRows,
      simulatedLiveMinutes,
      spsById,
    ]
  );
  const liveAttendanceBlueprintRooms = useMemo(() => {
    if (!liveExtraRoomCount) return liveBlueprintBaseRooms;
    const extraRooms = Array.from({ length: liveExtraRoomCount }, (_, extraIndex) => {
      const roomNumber = liveBlueprintBaseHighestRoomNumber + extraIndex + 1;
      const roomName = buildRoomLabelFromTemplate(getRoomTypeLabel(roomNamingContext), roomNumber, roomNamingContext);
      const adjustmentKey = `${LIVE_ROOM_BOARD_ADJUSTMENT_KEY}:${roomNumber}`;
      return {
        key: `blueprint-extra-room-${roomNumber}`,
        roomName,
        assignment: null,
        sp: null,
        spName: "",
        initials: String(roomNumber),
        checkedAt: "",
        actionTimestamp: "",
        status: "empty" as const,
        statusLabel: "Standby / Overflow",
        isCurrentRotationRoom: false,
        issueNote: "Temporary extra room",
        delayMinutes: 0,
        learnerLabel: "Overflow / standby",
        encounterLabel: "Case not assigned",
        standbyAssignment: null,
        standbySp: null,
        standbySpName: "",
        standbyExpanded: false,
        adjustmentKey,
        isTemporaryRoom: true,
        assignmentSource: "missing" as const,
      };
    });
    return [...liveBlueprintBaseRooms, ...extraRooms];
  }, [liveBlueprintBaseHighestRoomNumber, liveBlueprintBaseRooms, liveExtraRoomCount, roomNamingContext]);
  const liveVisibleRoomCount = liveAttendanceBlueprintRooms.length;
  const liveDisplayedPrimaryAssignmentIds = useMemo(
    () =>
      new Set(
        liveAttendanceBlueprintRooms
          .map((room) => asText(room.assignment?.id))
          .filter(Boolean)
      ),
    [liveAttendanceBlueprintRooms]
  );
  const liveUnmappedConfirmedAssignments = useMemo(
    () =>
      confirmedAssignments.filter((assignment) => {
        const assignmentId = asText(assignment.id);
        return assignmentId && !liveDisplayedPrimaryAssignmentIds.has(assignmentId);
      }),
    [confirmedAssignments, liveDisplayedPrimaryAssignmentIds]
  );
  const liveAttendanceLogRows = useMemo(
    () =>
      liveAttendanceBlueprintRooms
        .filter((room) => room.assignment || room.sp)
        .map((room) => ({
          key: room.key,
          roomName: room.roomName,
          spName: room.spName || "SP TBD",
          checkedAt: room.checkedAt,
          status: room.status,
          statusLabel: room.statusLabel,
          sortTime: room.actionTimestamp ? Date.parse(room.actionTimestamp) : 0,
        }))
        .sort((a, b) => {
          const roomCompare = compareRoomLabels(a.roomName, b.roomName);
          if (roomCompare !== 0) return roomCompare;
          const aChecked = a.status === "checked_in" ? 1 : 0;
          const bChecked = b.status === "checked_in" ? 1 : 0;
          if (aChecked !== bChecked) return bChecked - aChecked;
          return b.sortTime - a.sortTime;
        })
        .slice(0, 8),
    [liveAttendanceBlueprintRooms]
  );
  const liveBlueprintStaffedCount = liveAttendanceBlueprintRooms.filter((room) => Boolean(room.assignment)).length;
  const liveBlueprintCheckedCount = liveAttendanceBlueprintRooms.filter((room) => room.status === "checked_in").length;
  const liveBlueprintLateCount = liveAttendanceBlueprintRooms.filter((room) => room.status === "late").length;
  const liveBlueprintNoShowCount = liveAttendanceBlueprintRooms.filter((room) => room.status === "no_show").length;
  const liveBlueprintAwaitingCount = liveAttendanceBlueprintRooms.filter((room) => room.status === "awaiting").length;
  const liveLearnerPresenceTokens = useMemo(
    () =>
      liveAttendanceBlueprintRooms
        .filter((room) => isAssignedLearnerRoomLabel(room.learnerLabel))
        .flatMap((room, roomIndex) =>
          room.learnerLabel
            .split(",")
            .map((name) => name.trim())
            .filter(Boolean)
            .map((learnerName, learnerIndex) => {
              const attendanceKey = getLearnerAttendanceKey(currentLiveReferenceRound?.key, room.roomName, learnerName);
              const record = liveLearnerAttendanceRecords[attendanceKey] || null;
              const initialSeed = learnerName.replace(/[^A-Za-z0-9]/g, "");
              const initials = (initialSeed.slice(0, 2) || String(roomIndex + learnerIndex + 1)).toUpperCase();
              const isCurrentRoom = currentLiveBlock?.tone === "rotation" && room.isCurrentRotationRoom;
              const nextRoom =
                nextLiveBlock && nextLiveBlock.rooms.some((label) => compareRoomLabels(label, room.roomName) === 0);
              const storedStatus = record?.status || "expected";
              const displayStatus: LearnerAttendanceStatus =
                storedStatus === "arrived" && isCurrentRoom
                  ? "in_room"
                  : storedStatus === "expected" && isCurrentRoom
                    ? "expected"
                    : storedStatus;
              const state =
                displayStatus === "in_room" || displayStatus === "completed"
                  ? "roomed"
                  : displayStatus === "arrived"
                    ? "arrived"
                    : displayStatus === "late"
                      ? "late"
                      : displayStatus === "absent"
                        ? "absent"
                        : nextRoom
                          ? "next"
                          : "queued";
              return {
                key: `${room.key}-learner-token-${learnerIndex}`,
                attendanceKey,
                roomKey: room.key,
                roomName: room.roomName,
                learnerName,
                initials,
                state,
                status: displayStatus,
                storedStatus,
                updatedAt: record?.updatedAt || "",
                isCurrentRoom,
              };
            })
        ),
    [
      currentLiveBlock?.tone,
      currentLiveReferenceRound?.key,
      liveAttendanceBlueprintRooms,
      liveLearnerAttendanceRecords,
      nextLiveBlock,
    ]
  );
  const liveLearnerArrivedCount = liveLearnerPresenceTokens.filter((token) =>
    ["arrived", "in_room", "completed"].includes(token.status)
  ).length;
  const liveLearnerInRoomCount = liveLearnerPresenceTokens.filter((token) => token.status === "in_room").length;
  const liveLearnerMissingCount = liveLearnerPresenceTokens.filter((token) =>
    token.status === "late" || token.status === "absent" || (token.isCurrentRoom && token.status === "expected")
  ).length;
  const liveAnnouncementQueue = useMemo(() => {
    const nextIndex = nextLiveBlock ? liveFlowBlocks.findIndex((block) => block.key === nextLiveBlock.key) : -1;
    const queueStartIndex = nextIndex >= 0 ? nextIndex : Math.max(liveFlowBlocks.findIndex((block) => block.startMinutes > simulatedLiveMinutes), 0);
    return liveFlowBlocks.slice(queueStartIndex, queueStartIndex + 4).map((block, index) => ({
      ...block,
      countdownLabel:
        simulatedLiveMinutes < block.startMinutes
          ? `${Math.max(block.startMinutes - simulatedLiveMinutes, 0)}m to call`
          : simulatedLiveMinutes >= block.endMinutes
            ? "Complete"
            : `${Math.max(block.endMinutes - simulatedLiveMinutes, 0)}m remaining`,
      queueRole: index === 0 ? "next" : "queued",
      announcementText: getLiveFlowAnnouncementCopy(block),
    }));
  }, [liveFlowBlocks, nextLiveBlock, simulatedLiveMinutes]);
  const liveCloseoutItems = [
    { label: "Checked in", value: String(liveBlueprintCheckedCount), detail: `${liveBlueprintStaffedCount} staffed` },
    { label: "Learners arrived", value: `${liveLearnerArrivedCount}/${liveLearnerPresenceTokens.length}`, detail: `${liveLearnerInRoomCount} in rooms · ${liveLearnerMissingCount} alerts` },
    { label: "No-show", value: String(liveBlueprintNoShowCount), detail: liveBlueprintNoShowCount > 0 ? "Needs follow-up" : "No active no-show flags" },
    { label: "Payroll ready", value: `${payrollReadyCount}/${Math.max(confirmedCount, payrollReadyCount)}`, detail: "Confirmed attendance ready for payroll review" },
  ];
  const liveAttendanceAllPrimaryArrived =
    liveBlueprintStaffedCount > 0 &&
    liveBlueprintCheckedCount >= liveBlueprintStaffedCount &&
    liveBlueprintLateCount === 0 &&
    liveBlueprintNoShowCount === 0 &&
    liveBlueprintAwaitingCount === 0 &&
    liveRoomMissingCount === 0;
  const liveBlueprintHallwaySplitIndex = Math.ceil(liveVisibleRoomCount / 2);
  const liveBlueprintTopRooms = liveAttendanceBlueprintRooms.slice(0, liveBlueprintHallwaySplitIndex);
  const liveBlueprintBottomRooms = liveAttendanceBlueprintRooms.slice(liveBlueprintHallwaySplitIndex);
  const liveBlueprintMaxHallwayRooms = Math.max(liveBlueprintTopRooms.length, liveBlueprintBottomRooms.length, 1);
  const liveBlueprintRoomCardMinWidth = liveVisibleRoomCount > 7 ? 190 : 128;
  const liveBlueprintWallMinWidth =
    liveVisibleRoomCount > 7
      ? liveBlueprintMaxHallwayRooms * liveBlueprintRoomCardMinWidth + Math.max(liveBlueprintMaxHallwayRooms - 1, 0) * 8
      : 0;
  const compactLiveFlowRailBlocks = useMemo(() => {
    if (!liveFlowBlocks.length) return [] as typeof liveFlowBlocks;
    const selectedIndex = selectedLiveFlowBlock
      ? liveFlowBlocks.findIndex((block) => block.key === selectedLiveFlowBlock.key)
      : -1;
    const anchorIndex = selectedIndex >= 0 ? selectedIndex : currentLiveBlockIndex >= 0 ? currentLiveBlockIndex : 0;
    const startIndex = Math.max(anchorIndex - 1, 0);
    const endIndex = Math.min(startIndex + 5, liveFlowBlocks.length);
    return liveFlowBlocks.slice(startIndex, endIndex);
  }, [currentLiveBlockIndex, liveFlowBlocks, selectedLiveFlowBlock]);
  useEffect(() => {
    if (typeof window === "undefined" || !id) return;

    const storageKey = getLiveAttendancePanelStorageKey(id);
    const savedState = window.sessionStorage.getItem(storageKey);
    if (!liveAttendanceAllPrimaryArrived || liveBlueprintLateCount > 0 || liveBlueprintNoShowCount > 0 || liveRoomMissingCount > 0) {
      setLiveAttendanceToolsExpanded(true);
      return;
    }
    if (savedState === "expanded") {
      setLiveAttendanceToolsExpanded(true);
      return;
    }
    if (savedState === "collapsed") {
      setLiveAttendanceToolsExpanded(false);
      return;
    }
    setLiveAttendanceToolsExpanded(false);
  }, [
    id,
    liveAttendanceAllPrimaryArrived,
    liveBlueprintLateCount,
    liveBlueprintNoShowCount,
    liveRoomMissingCount,
  ]);
  const needsOutreachCount = useMemo(
    () =>
      pollResponderEntries.filter(
        (entry) => !entry.isAssigned || entry.pollResponseStatus === "no_response"
      ).length,
    [pollResponderEntries]
  );
  const suggestedAssignmentRows = useMemo(() => {
    const rows = pollResponderEntries.filter((entry) => entry.pollResponseStatus !== "not_available");
    return rows.filter((entry) => {
      if (suggestedAssignmentFilter === "all") return true;
      if (suggestedAssignmentFilter === "available") return entry.pollResponseStatus === "available";
      if (suggestedAssignmentFilter === "confirmed") return entry.isConfirmed;
      if (suggestedAssignmentFilter === "needs_outreach") return !entry.isAssigned || entry.pollResponseStatus === "no_response";
      if (suggestedAssignmentFilter === "backup") return entry.pollResponseStatus === "maybe" || entry.assignmentStatus === "backup";
      return true;
    });
  }, [pollResponderEntries, suggestedAssignmentFilter]);
  const matchMakerRankedEntries = useMemo(() => {
    const rankByResponse = {
      available: 1,
      maybe: 2,
      no_response: 3,
      not_available: 4,
    } satisfies Record<PollResponseStatus, number>;

    return [...pollResponderEntries].sort((a, b) => {
      const priorityA = a.isConfirmed ? 0 : rankByResponse[a.pollResponseStatus];
      const priorityB = b.isConfirmed ? 0 : rankByResponse[b.pollResponseStatus];
      if (priorityA !== priorityB) return priorityA - priorityB;

      if (a.isAssigned !== b.isAssigned) return a.isAssigned ? -1 : 1;

      const availabilityCompare =
        getAvailabilityMatchRank(a.availabilityMatch) -
        getAvailabilityMatchRank(b.availabilityMatch);
      if (availabilityCompare !== 0) return availabilityCompare;

      if (a.isActive !== b.isActive) return a.isActive ? -1 : 1;

      return getFullName(a.sp).localeCompare(getFullName(b.sp));
    });
  }, [pollResponderEntries]);
  const matchMakerTopMatches = useMemo(
    () =>
      matchMakerRankedEntries
        .filter(
          (entry) =>
            entry.assignmentStatus !== "declined" &&
            entry.pollResponseStatus !== "not_available"
        )
        .slice(0, Math.max(needed, 1)),
    [matchMakerRankedEntries, needed]
  );
  const matchMakerBackupMatches = useMemo(
    () =>
      matchMakerRankedEntries.filter(
        (entry) =>
          (entry.pollResponseStatus === "maybe" ||
            entry.pollResponseStatus === "no_response") &&
          entry.assignmentStatus !== "declined"
      ),
    [matchMakerRankedEntries]
  );
  const matchMakerAvoidList = useMemo(
    () =>
      matchMakerRankedEntries.filter(
        (entry) =>
          entry.pollResponseStatus === "not_available" ||
          entry.assignmentStatus === "declined"
      ),
    [matchMakerRankedEntries]
  );
  const pollResponseSummary = useMemo(() => {
    const selectedIds = Array.from(new Set(activePollSelectedSpIds.map((item) => item.trim()).filter(Boolean)));
    const availableCount = pollResponderEntries.filter((entry) => entry.pollResponseStatus === "available").length;
    const maybeCount = pollResponderEntries.filter((entry) => entry.pollResponseStatus === "maybe").length;
    const notAvailableCount = pollResponderEntries.filter((entry) => entry.pollResponseStatus === "not_available").length;
    const respondedCount = availableCount + maybeCount + notAvailableCount;
    return {
      totalSelected: selectedIds.length,
      availableCount,
      maybeCount,
      notAvailableCount,
      noResponseCount: Math.max(0, selectedIds.length - respondedCount),
    };
  }, [activePollSelectedSpIds, pollResponderEntries]);
  const defaultRelatedKeyword = useMemo(() => getDefaultRelatedEventKeyword(event?.name), [event?.name]);
  const facultyEmails = useMemo(() => {
    const matches = [trainingFacultyText, facultyEmailText]
      .join(" ")
      .match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi) || [];
    return Array.from(new Set(matches.map((item) => item.trim())));
  }, [facultyEmailText, trainingFacultyText]);
  useEffect(() => {
    setSelectedPollSpIds(pollSelectedSpIdsFromMetadata);
  }, [pollSelectedSpIdsFromMetadata]);
  const trainingEmailDateLabel =
    formatEventDateText(normalEventTrainingDateText, importedYearHint) ||
    normalEventTrainingDateText ||
    sessionSummaryLabel ||
    eventDateLabel ||
    "Date TBD";
  const trainingEmailTimeLabel = normalEventTrainingTimeText || summaryTimeLabel || "Time TBD";
  const trainingEmailSubject = `${event?.name || "Event"}: SP Training - ${trainingEmailDateLabel}`;
  const trainingEmailBody = [
    "SPs,",
    "",
    `In preparation for ${event?.name || "this"} SP training, please review the following:`,
    "",
    `• Date: ${trainingEmailDateLabel}`,
    `• Time: ${trainingEmailTimeLabel}`,
    `• Zoom Link: ${trainingMetadata.zoom_url || "INPUT ZOOM LINK"}`,
    `• Password: ${trainingMetadata.training_password || "INPUT PASSWORD"}`,
    `• Case: ${trainingMetadata.case_name || "Name of CASE"}`,
    `• Sim Contact: ${trainingSimContact || "Sim Team Assigned"}`,
    "",
    "Thank you,",
    "",
    me?.fullName || me?.scheduleName || me?.email || "CFSP",
  ].join("\n");
  const trainingMailtoHref = buildMailtoHref({
    to: me?.email || "",
    cc: facultyEmails,
    bcc: assignedBccEmails,
    subject: trainingEmailSubject,
    body: trainingEmailBody,
  });
  function togglePollSp(spId: string) {
    setSelectedPollSpIds((current) =>
      current.includes(spId)
        ? current.filter((id) => id !== spId)
        : [...current, spId]
    );
  }

  function selectAllVisiblePollCandidates(candidateIds: string[]) {
    setSelectedPollSpIds(candidateIds);
  }

  function clearPollSelection() {
    setSelectedPollSpIds([]);
  }

  async function persistPollExclusions(spIds: string[], emails: string[], successMessage: string) {
    await persistPollMetadata(
      {
        excludedSpIds: Array.from(new Set(spIds.map((spId) => String(spId).trim()).filter(Boolean))).join(","),
        excludedSpEmails: Array.from(new Set(emails.map((email) => normalizeEmail(email)).filter(Boolean))).join(","),
      },
      successMessage
    );
  }

  function addPollSelection(spIds: string[], successMessage: string) {
    const normalized = Array.from(new Set(spIds.map((item) => String(item)).filter(Boolean)));
    if (!normalized.length) {
      setEventSaveError("No matching SPs are ready to add to this poll.");
      return;
    }
    setSelectedPollSpIds((current) => Array.from(new Set([...current, ...normalized])));
    showSuccessMessage(successMessage);
  }

  function handleAddRecommendedToPoll() {
    addPollSelection(
      recommendedPollMatches
        .filter((entry) => entry.emailReady)
        .slice(0, Math.max(needed || 0, 1))
        .map((entry) => entry.sp.id),
      "Recommended SPs added to poll."
    );
  }

  function handleAddAllFilteredToPoll() {
    addPollSelection(
      pollMatchEntries.filter((entry) => entry.emailReady && !entry.selected && !entry.excluded).map((entry) => entry.sp.id),
      "Filtered SPs added to poll."
    );
  }

  function handleSelectTopPollCandidates(count: number) {
    addPollSelection(
      pollMatchEntries
        .filter((entry) => entry.emailReady && !entry.selected && !entry.excluded)
        .slice(0, count)
        .map((entry) => entry.sp.id),
      `Selected top ${count} candidate${count === 1 ? "" : "s"} for polling.`
    );
  }

  function handleTogglePollCandidate(spId: string) {
    togglePollSp(spId);
  }

  async function handleExcludeSelectedPollCandidates() {
    const selectedEntries = pollMatchEntries.filter((entry) => entry.selected);
    if (!selectedEntries.length) {
      setEventSaveError("Select at least one poll candidate before excluding.");
      return;
    }
    const nextIds = [...excludedPollSpIdsFromMetadata, ...selectedEntries.map((entry) => entry.sp.id)];
    const nextEmails = [
      ...excludedPollSpEmailsFromMetadata,
      ...selectedEntries.map((entry) => entry.email || "").filter(Boolean),
    ];
    setSelectedPollSpIds((current) => current.filter((spId) => !selectedEntries.some((entry) => entry.sp.id === spId)));
    await persistPollExclusions(nextIds, nextEmails, "Selected poll candidates excluded.");
  }

  async function handleResetPollExclusions() {
    await persistPollExclusions([], [], "Poll exclusions cleared.");
  }

  function handleRemoveFromPoll(spId: string) {
    setSelectedPollSpIds((current) => current.filter((id) => id !== spId));
    showSuccessMessage("Removed from poll.");
  }

  async function persistPollMetadata(partial: Partial<PollMetadata>, successMessage: string) {
    const nextNotes = upsertPollMetadata(eventEditor.notes, partial);
    return persistTrainingNotes(nextNotes, successMessage);
  }

  function getImportedPollNoteForSpId(spId: string) {
    return asText(importedPollResponsesBySpId.get(String(spId))?.responseNote);
  }

  async function handlePollImportFile(file: File | null) {
    if (pollImportSaving) {
      setPollImportError("Upload already in progress. Please wait for the current poll import to finish.");
      setPollImportSuccess("");
      setPollImportSummary(null);
      if (pollImportInputRef.current) pollImportInputRef.current.value = "";
      return;
    }

    if (!file) {
      setPollImportError("Choose a CSV, XLSX, or XLS poll results file to upload.");
      setPollImportSuccess("");
      setPollImportSummary(null);
      return;
    }

    const lowerName = file.name.toLowerCase();
    const supportedFormat =
      lowerName.endsWith(".csv") ||
      lowerName.endsWith(".xlsx") ||
      lowerName.endsWith(".xls") ||
      /csv|spreadsheet|excel/i.test(file.type);

    if (!supportedFormat) {
      setPollImportError("Unsupported file format. Upload a CSV, XLSX, or XLS poll export.");
      setPollImportSuccess("");
      setPollImportSummary(null);
      if (pollImportInputRef.current) pollImportInputRef.current.value = "";
      return;
    }

    if (file.size <= 0) {
      setPollImportError("That file is empty. Upload a poll export with responder rows.");
      setPollImportSuccess("");
      setPollImportSummary(null);
      if (pollImportInputRef.current) pollImportInputRef.current.value = "";
      return;
    }

    setPollImportSaving(true);
    setPollImportError("");
    setPollImportSuccess("");
    setPollImportSummary(null);
    setPollImportDebugInfo(null);
    setEventSaveError("");
    setEventSaveMessage("");

    try {
      console.info("CFSP poll import upload start", {
        eventId: id,
        fileName: file.name,
        fileSize: file.size,
        fileType: file.type,
      });

      const formData = new FormData();
      formData.append("file", file, file.name);
      console.info("CFSP poll import FormData ready", {
        eventId: id,
        hasFile: formData.has("file"),
        fileName: file.name,
      });

      const response = await fetch(`/api/events/${encodeURIComponent(id)}/poll-import`, {
        method: "POST",
        body: formData,
        credentials: "include",
      });
      const body = (await response.json().catch(() => null)) as PollImportApiResponse | null;

      console.info("CFSP poll import response received", {
        eventId: id,
        ok: response.ok,
        status: response.status,
        summary: body?.summary,
        detectedHeaders: body?.debug?.detectedHeaders,
      });

      if (!response.ok || !body?.ok) {
        if (body?.debug) setPollImportDebugInfo(body.debug);
        throw new Error(asText(body?.error) || `Poll import failed (${response.status}).`);
      }

      setPollImportError("");
      if (body.debug) setPollImportDebugInfo(body.debug);
      const importedResponses = body.importedPollResponses || [];
      const importSummary = body.summary || getPollImportSummaryFromResponses(importedResponses);
      const latestUploadAt =
        (body.eventNotes ? parsePollMetadata(body.eventNotes).pollImportCreatedAt : "") || new Date().toISOString();
      if (body.eventNotes) {
        setEventEditor((current) => ({ ...current, notes: body.eventNotes || current.notes }));
        setEvent((current) => (current ? { ...current, notes: body.eventNotes || current.notes } : current));
      }
      setPollImportSummary(importSummary);
      setPollImportSuccess(buildPollImportSuccessMessage(importSummary, latestUploadAt));
      setPollImportIgnoredUnmatched(false);
      showSuccessMessage(buildPollImportSuccessMessage(importSummary, latestUploadAt));
      if ((importSummary.assignmentNotesUpdated || 0) > 0) {
        await refreshData();
      }
    } catch (error) {
      console.error("CFSP poll import failed", {
        eventId: id,
        error: error instanceof Error ? error.message : error,
      });
      setPollImportSuccess("");
      setPollImportSummary(null);
      setPollImportError(error instanceof Error ? error.message : "Could not import poll responses.");
    } finally {
      setPollImportSaving(false);
      if (pollImportInputRef.current) pollImportInputRef.current.value = "";
    }
  }

  async function handleExcludeImportedResponder(spId: string, email?: string) {
    const nextIds = Array.from(new Set([...excludedPollSpIdsFromMetadata, String(spId)].filter(Boolean)));
    const nextEmails = Array.from(
      new Set([...excludedPollSpEmailsFromMetadata, normalizeEmail(email || "")].filter(Boolean))
    );
    await persistPollExclusions(nextIds, nextEmails, "Imported responder excluded from staffing suggestions.");
  }

  async function handleMarkImportedBackup(spId: string) {
    const existingAssignment = assignmentsBySpId.get(String(spId));
    if (existingAssignment) {
      await handleStatusChange(existingAssignment, "backup");
      return;
    }
    const pollNote = getImportedPollNoteForSpId(spId);
    await assignMultipleSpIds([spId], "Responder added as backup.", {
      status: "backup",
      confirmed: false,
      notesBySpId: pollNote ? { [String(spId)]: pollNote } : undefined,
    });
  }

  async function handleCreatePoll() {
    if (!selectedPollSpIds.length || !pollSelectedEmails.length) {
      setEventSaveError("Select at least one candidate SP with an email address to create a poll.");
      return;
    }

    setPollSaving(true);
    try {
      await persistPollMetadata(
        {
          pollCreatedAt: new Date().toISOString(),
          pollSentAt: pollMetadata.pollSentAt,
          pollSelectedSpIds: Array.from(new Set(selectedPollSpIds.map((spId) => String(spId).trim()).filter(Boolean))).join(","),
          pollSelectedSpEmails: Array.from(new Set(pollSelectedEmails.map((email) => normalizeEmail(email)).filter(Boolean))).join(","),
          pollStatus: "draft_ready",
        },
        "Availability poll created."
      );
    } finally {
      setPollSaving(false);
    }
  }

  const pollEmailSubject = `${event?.name || "Event"}: CFSP Availability Poll`;
  const pollEmailBody = `SPs,

We are checking availability for the following event:

Event:
${event?.name || "TBD"}

Date/Time:
${pollEventDateTimeSummary}

Training:
${pollTrainingSummary}

Location:
${pollLocationSummary}

Please submit your availability in CFSP using the link below:

${eventPollLink}

Use this link to view the poll. You'll be asked to log in or create an SP account before submitting your response.

Submitting availability does not guarantee assignment. We will follow up once staffing is finalized.

Thank you,
Cory`;

  const pollMailtoHref = buildMailtoHref({
    to: me?.email || "",
    cc: facultyEmails,
    bcc: pollSelectedEmails.length ? pollSelectedEmails : pollSelectedSpEmailsFromMetadata,
    subject: pollEmailSubject,
    body: pollEmailBody,
  });

  async function handleDraftPollingEmail() {
    if (!pollSelectedEmails.length && !pollSelectedSpEmailsFromMetadata.length) {
      setEventSaveError("Create a poll with selected SP emails before drafting the polling email.");
      return;
    }

    window.location.href = pollMailtoHref;

    if (selectedPollSpIds.length || pollSelectedEmails.length) {
      setPollSaving(true);
      try {
        await persistPollMetadata(
          {
            pollCreatedAt: pollMetadata.pollCreatedAt || new Date().toISOString(),
            pollSentAt: pollMetadata.pollSentAt,
            pollSelectedSpIds: Array.from(
              new Set((selectedPollSpIds.length ? selectedPollSpIds : pollSelectedSpIdsFromMetadata).map((spId) => String(spId).trim()).filter(Boolean))
            ).join(","),
            pollSelectedSpEmails: Array.from(
              new Set((pollSelectedEmails.length ? pollSelectedEmails : pollSelectedSpEmailsFromMetadata).map((email) => normalizeEmail(email)).filter(Boolean))
            ).join(","),
            pollStatus: "draft_ready",
          },
          "Polling email draft opened."
        );
      } finally {
        setPollSaving(false);
      }
    }
  }

  async function handleMarkPollSent() {
    if (!pollMetadata.pollCreatedAt && !selectedPollSpIds.length) {
      setEventSaveError("Create a poll before marking it sent.");
      return;
    }

    setPollSaving(true);
    try {
      await persistPollMetadata(
        {
          pollCreatedAt: pollMetadata.pollCreatedAt || new Date().toISOString(),
          pollSentAt: new Date().toISOString(),
          pollSelectedSpIds: Array.from(
            new Set((selectedPollSpIds.length ? selectedPollSpIds : pollSelectedSpIdsFromMetadata).map((spId) => String(spId).trim()).filter(Boolean))
          ).join(","),
          pollSelectedSpEmails: Array.from(
            new Set((pollSelectedEmails.length ? pollSelectedEmails : pollSelectedSpEmailsFromMetadata).map((email) => normalizeEmail(email)).filter(Boolean))
          ).join(","),
          pollStatus: "sent",
        },
        "Availability poll marked sent."
      );
    } finally {
      setPollSaving(false);
    }
  }
  const pollSelectedCount = selectedPollSpIds.length || pollSelectedSpIdsFromMetadata.length;
  const pollReadyEmailCount = pollSelectedEmails.length || pollSelectedSpEmailsFromMetadata.length;
  const pollCreatedLabel = formatUploadedTimestamp(pollMetadata.pollCreatedAt);
  const pollSentLabel = formatUploadedTimestamp(pollMetadata.pollSentAt);
  const latestPollImportLabel = formatUploadedTimestamp(pollMetadata.pollImportCreatedAt);
  const staffingReadinessStatus: WorkflowReadinessStatus = noSpStaffingRequired
    ? "Optional"
    : needed > 0 && confirmedCount >= needed
      ? "Ready"
      : selectedStaffingCount > 0 || contactedAssignmentCount > 0
        ? "Needs Action"
        : "Not Started";
  const facultyReadinessStatus: WorkflowReadinessStatus = facultyReadinessComplete ? "Ready" : "Needs Action";
  const scheduleReadinessStatus: WorkflowReadinessStatus =
    scheduleCompleted
      ? "Ready"
      : scheduleInProgress
        ? "In Progress"
        : rotationRounds.length && summaryTimeLabel !== "Time TBD"
      ? "Ready"
      : sessions.length || asText(event?.date_text)
        ? "Needs Action"
        : "Not Started";
  const emailReadinessStatus: WorkflowReadinessStatus =
    hiringEmailSent && confirmationEmailSent
      ? "Ready"
      : outreachProgressLabel === "In progress" || outreachProgressLabel === "Draft opened"
        ? "In Progress"
        : "Not Started";
  const trainingReadinessStatus: WorkflowReadinessStatus = trainingNotRequired
    ? "Optional"
    : normalEventTrainingComplete || normalEventTrainingReady
      ? "Ready"
      : trainingBlocksEvent
        ? "Blocked"
      : trainingRequiredExplicit || facultyLedTraining || internalTraining || normalEventTrainingHasInfo
        ? "Needs Action"
        : "Not Started";
  const platformReadinessStatus: WorkflowReadinessStatus =
    eventMeta.isVirtualSp || selectedModalityLabel === "Virtual" || selectedModalityLabel === "Hybrid"
      ? hasZoomReady || Boolean(normalEventTrainingLink)
        ? "Ready"
        : "Blocked"
      : "Optional";
  const recordingReadinessStatus: WorkflowReadinessStatus =
    eventRecordingStatus.value === "recording_in_progress"
    ? "Needs Action"
    : eventRecordingStatus.value === "recording_planned" || eventRecordingStatus.value === "recorded"
      ? "Ready"
      : eventRecordingStatus.value === "missing"
        ? "Needs Action"
        : "Optional";
  const planningLivePreviewPrimaryBlock = currentLiveBlock || nextLiveBlock || liveFlowBlocks[0] || null;
  const planningLivePreviewPrimaryBlockIndex = planningLivePreviewPrimaryBlock
    ? liveFlowBlocks.findIndex((block) => block.key === planningLivePreviewPrimaryBlock.key)
    : -1;
  const planningLivePreviewBlockStartIndex =
    planningLivePreviewPrimaryBlockIndex >= 0 ? planningLivePreviewPrimaryBlockIndex : 0;
  const planningLivePreviewBlocks = liveFlowBlocks.slice(
    planningLivePreviewBlockStartIndex,
    planningLivePreviewBlockStartIndex + 5
  );
  const planningLivePreviewNextBlock =
    planningLivePreviewPrimaryBlockIndex >= 0
      ? liveFlowBlocks[planningLivePreviewPrimaryBlockIndex + 1] || null
      : nextLiveBlock || null;
  const planningLivePreviewAlerts = [
    staffingRelevant && shortageCount > 0
      ? `${shortageCount} primary SP${shortageCount === 1 ? "" : "s"} still needed`
      : "",
    !rotationRounds.length ? "Schedule blocks are not built yet" : "",
    !hasRoomsBuilt || effectiveRoomCount <= 0 ? "Room plan needs review" : "",
    ...learnerPlannerMissingSignals,
    materialsWorkflowNeedsAction ? `Materials need attention: ${materialsStatusLabel}` : "",
    recordingReadinessStatus === "Needs Action" ? "Recording status needs review" : "",
    ...liveSupportNeeds.map((item) => item.label),
  ].filter(Boolean);
  const planningLivePreviewReadinessLabel =
    planningLivePreviewAlerts.length === 0 && eventRiskLevel.tone === "green"
